func (c *PolicyQuotaController) handleUpsert(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.Namespace
	name := cnp.Name

	c.mu.Lock()
	defer c.mu.Unlock()

	// If this is an update of an existing policy in the same namespace, count stays the same
	// If this is a new policy, increment the count
