func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name            string
		maxPerNamespace int
		currentCount    int
		expectError     bool
	}{
		{
			name:            "under_quota",
			maxPerNamespace: 10,
			currentCount:    5,
			expectError:     false,
		},
		{
			name:            "at_quota",
			maxPerNamespace: 10,
			currentCount:    10,
			expectError:     true,
		},
		{
			name:            "over_quota",
			maxPerNamespace: 10,
			currentCount:    15,
			expectError:     true,
		},
		{
			name:            "unlimited_quota",
			maxPerNamespace: 0,
			currentCount:    100,
			expectError:     false,
		},
		{
			name:            "empty_namespace",
			maxPerNamespace: 10,
			currentCount:    0,
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			logger := logrus.New()
			mockResource := &MockResource{
				eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
			}

			controller := NewPolicyQuotaController(logger, mockResource, tt.maxPerNamespace)
			controller.namespacePolicyCounts["test-namespace"] = tt.currentCount

			err := controller.CheckQuota("test-namespace")

			if (err != nil) != tt.expectError {
