// TestNewPolicyQuotaController tests the controller initialization.
func TestNewPolicyQuotaController(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	if controller == nil {
		t.Fatal("Expected controller to be created, got nil")
	}
	if controller.maxPerNamespace != 10 {
		t.Errorf("Expected maxPerNamespace to be 10, got %d", controller.maxPerNamespace)
	}
	if len(controller.namespacePolicyCounts) != 0 {
		t.Errorf("Expected empty namespace policy counts, got %d entries", len(controller.namespacePolicyCounts))
	}
}

// TestCheckQuota tests the quota checking functionality.
func TestCheckQuota(t *testing.T) {
	tests := []struct {
		name            string
		maxPerNamespace int
		currentCount    int
		expectError     bool
	}{
		{
			name:            "under_quota",
			maxPerNamespace: 10,
			currentCount:    5,
			expectError:     false,
		},
		{
			name:            "at_quota",
			maxPerNamespace: 10,
			currentCount:    10,
			expectError:     true,
		},
		{
			name:            "over_quota",
			maxPerNamespace: 10,
			currentCount:    15,
			expectError:     true,
		},
		{
			name:            "unlimited_quota",
			maxPerNamespace: 0,
			currentCount:    100,
			expectError:     false,
		},
		{
			name:            "empty_namespace",
			maxPerNamespace: 10,
			currentCount:    0,
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			logger := logrus.New()
			mockResource := &MockResource{
				eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
			}

			controller := NewPolicyQuotaController(logger, mockResource, tt.maxPerNamespace)
			controller.namespacePolicyCounts["test-namespace"] = tt.currentCount

			err := controller.CheckQuota("test-namespace")

			if (err != nil) != tt.expectError {
				t.Errorf("Expected error: %v, got error: %v", tt.expectError, err)
			}
		})
	}
}

// TestGetNamespacePolicyCount tests retrieving the policy count for a namespace.
func TestGetNamespacePolicyCount(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	// Test non-existent namespace
	if count := controller.GetNamespacePolicyCount("non-existent"); count != 0 {
		t.Errorf("Expected 0 for non-existent namespace, got %d", count)
	}

	// Set a count and test retrieval
	controller.namespacePolicyCounts["test-ns"] = 5
	if count := controller.GetNamespacePolicyCount("test-ns"); count != 5 {
		t.Errorf("Expected 5 for test-ns, got %d", count)
	}
}

// TestHandleUpsert tests the upsert event handling.
func TestHandleUpsert(t *testing.T) {
	logger := logrus.New()
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(logger, mockResource, 10)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	// Test handling the first upsert
	controller.handleUpsert(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after upsert, got %d", count)
	}

	// Handle another upsert (should not increment since this is the same policy update)
	controller.handleUpsert(cnp)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 1 {
		t.Errorf("Expected 1 policy after second upsert (same policy), got %d", count)
	}

	// Test upsert of a different policy in the same namespace
	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "test-ns",
		},
	}

	controller.handleUpsert(cnp2)

	if count := controller.GetNamespacePolicyCount("test-ns"); count != 2 {
		t.Errorf("Expected 2 policies after upsert of second policy, got %d", count)
	}
}

